import { auth } from "@/auth"
import { redirect } from "next/navigation"
import { LogoutButton } from "./components/logout-button"

export default async function AdminHomePage() {
  const session = await auth()

  if (!session?.user?.id) {
    redirect("/sign-in")
  }

  return (
    <main className="flex min-h-screen items-center justify-center bg-[#f3f4f6] px-4">
      <div className="rounded-2xl border border-gray-200 bg-white px-8 py-10 shadow-sm">
        <p className="text-xs font-semibold uppercase tracking-[0.25em] text-[#184f43]">Admin</p>
        <h1 className="mt-2 text-3xl font-bold text-gray-900">Hello World</h1>
        <p className="mt-2 text-sm text-gray-600">Admin dashboard scaffold ready.</p>
        <LogoutButton />
      </div>
    </main>
  )
}
